import React from 'react';
import { useState, useEffect } from 'react';
import { OAuth2 } from '@oasis-sh/react-native-oauth2';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';
const redirectUri = 'https://your-redirect-uri.com';

const App = () => {
  const [code, setCode] = useState('');
  const [accessToken, setAccessToken] = useState('');

  useEffect(() => {
    if (!code) return;
    OAuth2.exchangeAuthorizationCode(clientId, clientSecret, code, redirectUri).then((token) => {
      setAccessToken(token);
    });
  }, [code]);

  const handleLogin = () => {
    OAuth2.authorize(clientId, { scope: 'email' }).then((url) => {
      setCode(url);
    });
  };

  return (
    <div>
      <button onClick={handleLogin}>Log in with Google</button>
      {accessToken && <p>Access token: {accessToken}</p>}
    </div>
  );
};

export default App;